-- SPEC:D.2 — compiled metric view: repeat_rate (v1) @ grain=all · entity=semantic_customer
-- GENERATED by @brain/semantic-metrics compiler — DO NOT EDIT. Change the YAML + recompile.
-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW brain_serving.mv_metric_repeat_rate_all AS
WITH base AS (
  SELECT
    brand_id,
    SUM(CASE WHEN lifetime_orders >= 2 THEN 1 ELSE 0 END) AS repeat_customers,
    COUNT(DISTINCT brain_id) AS total_customers
  FROM brain_serving.semantic_customer
  WHERE identity_basis = 'deterministic'
    AND ${BRAND_PREDICATE}
  GROUP BY 1
)
SELECT
  brand_id,
  repeat_customers,
  total_customers,
  (CAST(repeat_customers AS double) / NULLIF(total_customers, 0)) AS repeat_rate
FROM base;
